9	// Valid state transitions — all other moves are rejected.
10	const TRANSITIONS = {
11	  SUBMITTED: ['UNDER_REVIEW'],
12	  UNDER_REVIEW: ['APPROVED', 'PARTIALLY_APPROVED', 'DENIED'],
13	  APPROVED: ['PAID', 'DISPUTED'],
14	  PARTIALLY_APPROVED: ['PAID', 'DISPUTED'],
15	  DENIED: ['DISPUTED'],
16	  PAID: [],
17	  DISPUTED: ['UNDER_REVIEW']
18	};
19	
20	function assertTransition(from, to) {
21	  if (!TRANSITIONS[from]?.includes(to)) {
22	    throw Object.assign(new Error(`Invalid transition: ${from} → ${to}`), { statusCode: 422 });
23	  }
24	}
25	
26	async function submitClaim(claimData) {
27	  const claim = new Claim({ ...claimData, status: 'SUBMITTED' });
28	  await claim.save();
29	  return claim;
30	}
31	
32	// Move to UNDER_REVIEW and run adjudication.
33	async function reviewClaim(claimId) {
34	  const claim = await Claim.findById(claimId);
35	  if (!claim) throw Object.assign(new Error('Claim not found'), { statusCode: 404 });
36	  assertTransition(claim.status, 'UNDER_REVIEW');
37	
38	  claim.status = 'UNDER_REVIEW';
39	  await claim.save();
40	
41	  return adjudicateClaim(claimId, 'INITIAL_SUBMISSION');
